package com.chaobo.scm.supplier.application.finance;
import com.chaobo.scm.common.error.*;import com.chaobo.scm.supplier.application.integration.InboundEventPayloadStore;import com.chaobo.scm.supplier.application.masterdata.MasterDataEventConsumeLogPort;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;
@Service public class BmsFinanceEventConsumerApplicationService{private static final String CONSUMER="supplier-finance";private final MasterDataEventConsumeLogPort inbox;private final SupplierFinanceApplicationService finance;private final SupplierFinanceLifecycleApplicationService lifecycle;private final InboundEventPayloadStore payloads;public BmsFinanceEventConsumerApplicationService(MasterDataEventConsumeLogPort inbox,SupplierFinanceApplicationService finance,SupplierFinanceLifecycleApplicationService lifecycle,InboundEventPayloadStore payloads){this.inbox=inbox;this.finance=finance;this.lifecycle=lifecycle;this.payloads=payloads;}@Transactional public void consume(BmsFinanceEvent event){var claim=inbox.claim("BMS",event.eventCode(),event.eventType(),CONSUMER,"BMS:"+event.eventCode());if(claim==MasterDataEventConsumeLogPort.ClaimResult.ALREADY_SUCCEEDED)return;if(claim==MasterDataEventConsumeLogPort.ClaimResult.IN_PROGRESS)throw new BusinessException(ErrorCode.IDEMPOTENCY_CONFLICT,"财务事件正在处理");payloads.save("BMS",event.eventCode(),CONSUMER,event);try{switch(event.eventType()){case "BmsReconciliationIssued","BmsReconciliationChanged"->finance.importStatement(event.statementNo(),event.supplierId(),event.currency(),event.amount(),event.sourceVersion());case "BmsReconciliationClosed"->lifecycle.closeFromBms(event.statementNo(),event.supplierId(),event.sourceVersion());case "BmsInvoiceValidated"->{if(event.invoiceId()==null)throw new BusinessException(ErrorCode.VALIDATION_FAILED,"发票ID不能为空");finance.recordInvoiceValidation(event.invoiceId(),event.passed(),event.message());}default->{inbox.markSucceeded("BMS",event.eventCode(),CONSUMER,true);return;}}inbox.markSucceeded("BMS",event.eventCode(),CONSUMER,false);}catch(RuntimeException exception){inbox.recordFailure("BMS",event.eventCode(),event.eventType(),CONSUMER,"BMS:"+event.eventCode(),exception.getMessage());throw exception;}}}
